def get_openapi_security_definitions(
    flat_dependant: Dependant,
) -> Tuple[Dict[str, Any], List[Dict[str, Any]]]:
    """
    Produce security definitions and operation-specific security requirements
    from a flat Dependant (dependency resolver) object.

    Returns a tuple with:
    - security_definitions: mapping of security scheme name to its schema declaration
    - operation_security: list of security requirement objects to be applied to the operation
    """
    security_definitions = {}
    operation_security = []
    for security_requirement in flat_dependant.security_requirements:
        security_definition = jsonable_encoder(
            security_requirement.security_scheme.model,
            by_alias=True,
            exclude_none=True,
        )
        security_name = security_requirement.security_scheme.scheme_name
        security_definitions[security_name] = security_definition
        operation_security.append({security_name: security_requirement.scopes})
    return security_definitions, operation_security


def get_openapi_operation_parameters(
    *,
    all_route_params: Sequence[ModelField],
    schema_generator: GenerateJsonSchema,
    model_name_map: ModelNameMap,
    field_mapping: Dict[
        Tuple[ModelField, Literal["validation", "serialization"]], JsonSchemaValue
    ],
    separate_input_output_schemas: bool = True,
) -> List[Dict[str, Any]]:
    """
    Convert a sequence of ModelField route parameters into the OpenAPI
    "parameters" list for an operation.

    Parameters are filtered by include_in_schema and translated using the
    provided schema generator and model name mapping.
    """
    parameters: List[Dict[str, Any]] = []
    for param in all_route_params:
        field_info = param.field_info
        field_info = cast(Param, field_info)
        if not field_info.include_in_schema:
            continue
        param_schema = get_schema_from_model_field(
            field=param,
            schema_generator=schema_generator,
            model_name_map=model_name_map,
            field_mapping=field_mapping,
            separate_input_output_schemas=separate_input_output_schemas,
        )
        parameter: Dict[str, Any] = {
            "name": param.alias,
            "in": field_info.in_.value,
            "required": param.required,
            "schema": param_schema,
        }
        if field_info.description:
            parameter["description"] = field_info.description
        if field_info.openapi_examples:
            parameter["examples"] = jsonable_encoder(field_info.openapi_examples)
        if field_info.deprecated:
            parameter["deprecated"] = True
        if getattr(field_info, "style", None) is not None:
            parameter["style"] = getattr(field_info, "style").value
        if getattr(field_info, "explode", None) is not None:
            parameter["explode"] = field_info.explode
        parameters.append(parameter)
    return parameters


def get_openapi_operation_request_body(
    *,
    body_field: Optional[ModelField],
    schema_generator: GenerateJsonSchema,
    model_name_map: ModelNameMap,
    field_mapping: Dict[
        Tuple[ModelField, Literal["validation", "serialization"]], JsonSchemaValue
    ],
    request_body_required: bool = True,
    separate_input_output_schemas: bool = True,
) -> Optional[Dict[str, Any]]:
    """
    Build the OpenAPI requestBody object for an operation given a Body field.

    Returns None if there is no body field or if the body should not be included.
    """
    if body_field is None:
        return None
    field_info = cast(Body, body_field.field_info)
    if not field_info.include_in_schema:
        return None

    media_type: Dict[str, Any] = {}
    schema = get_schema_from_model_field(
        field=body_field,
        schema_generator=schema_generator,
        model_name_map=model_name_map,
        field_mapping=field_mapping,
        separate_input_output_schemas=separate_input_output_schemas,
    )
    media_type["schema"] = schema

    if field_info.example is not None:
        media_type["example"] = jsonable_encoder(field_info.example)
    if field_info.examples:
        media_type["examples"] = jsonable_encoder(field_info.examples)

    request_body: Dict[str, Any] = {"content": {"application/json": media_type}}
    if field_info.description:
        request_body["description"] = field_info.description
    # Respect explicit required flag, otherwise use default
    request_body["required"] = request_body_required if request_body_required is not None else True
    return request_body


def generate_operation_id(route: routing.APIRoute) -> str:
    """
    Generate a unique operationId for the given APIRoute using FastAPI's
    helper generate_operation_id_for_path. Falls back to the endpoint name if needed.
    """
    if route.operation_id:
        return route.operation_id
    try:
        gen = generate_operation_id_for_path(route.path_format, route.methods)
        return gen
    except Exception:
        # Fallback to endpoint name
        view_name = getattr(route.endpoint, "__name__", None)
        if view_name:
            return view_name
        return f"operation_{abs(id(route))}"


def generate_operation_summary(route: routing.APIRoute) -> Optional[str]:
    """
    Attempt to derive a short summary for an operation from the endpoint's
    docstring (first line) or the route name.
    """
    func = route.endpoint
    doc = inspect.getdoc(func) or ""
    if doc:
        first_line = doc.splitlines()[0].strip()
        if first_line:
            return first_line
    # Fallback to route name or function name
    name = getattr(route, "name", None) or getattr(func, "__name__", None)
    return name


def get_openapi_operation_metadata(
    *,
    route: routing.APIRoute,
    dependant: Dependant,
    response_field: Optional[ModelField],
    response_class: Type[Response],
    status_code: int,
    schema_generator: GenerateJsonSchema,
    model_name_map: ModelNameMap,
    field_mapping: Dict[
        Tuple[ModelField, Literal["validation", "serialization"]], JsonSchemaValue
    ],
    generate_unique_operation_id: bool = True,
    separate_input_output_schemas: bool = True,
) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Construct OpenAPI operation metadata (operation object) and collect any
    new security definitions that arise from the route's dependencies.

    Returns a tuple of (operation_object, security_definitions).
    """
    operation: Dict[str, Any] = {}
    # Summary and description
    summary = generate_operation_summary(route)
    if summary:
        operation["summary"] = summary
    description = inspect.getdoc(route.endpoint)
    if description:
        operation["description"] = description

    # OperationId
    if generate_unique_operation_id:
        operation_id = generate_operation_id(route)
    else:
        operation_id = route.operation_id or None
    if operation_id:
        operation["operationId"] = operation_id

    # Tags
    if getattr(route, "tags", None):
        operation["tags"] = list(route.tags)

    # Deprecated
    if getattr(route, "deprecated", None):
        operation["deprecated"] = True

    # Dependencies: parameters and request body
    flat_dependant = get_flat_dependant(dependant)
    all_route_params = get_flat_params(flat_dependant)
    parameters = get_openapi_operation_parameters(
        all_route_params=all_route_params,
        schema_generator=schema_generator,
        model_name_map=model_name_map,
        field_mapping=field_mapping,
        separate_input_output_schemas=separate_input_output_schemas,
    )

    # Request body (if any)
    body_field: Optional[ModelField] = None
    for p in all_route_params:
        if p.field_info and isinstance(p.field_info, Body):
            body_field = p
            break

    request_body = get_openapi_operation_request_body(
        body_field=body_field,
        schema_generator=schema_generator,
        model_name_map=model_name_map,
        field_mapping=field_mapping,
        request_body_required=body_field.required if body_field is not None else False,
        separate_input_output_schemas=separate_input_output_schemas,
    )

    if parameters:
        operation["parameters"] = parameters
    if request_body:
        operation["requestBody"] = request_body

    # Responses
    responses: Dict[str, Any] = {}
    # Default response based on status code and response_class
    content: Dict[str, Any] = {}
    if response_class is JSONResponse or issubclass(response_class, JSONResponse):
        # assume application/json
        content["application/json"] = {"schema": {}}
        if response_field is not None:
            content["application/json"]["schema"] = get_schema_from_model_field(
                field=response_field,
                schema_generator=schema_generator,
                model_name_map=model_name_map,
                field_mapping=field_mapping,
                separate_input_output_schemas=separate_input_output_schemas,
            )
    # Build status code key
    status_code_str = str(status_code)
    responses[status_code_str] = {"description": http.client.responses.get(status_code, "")}
    if content:
        responses[status_code_str]["content"] = content

    # Add validation error response if applicable
    if status_code == HTTP_422_UNPROCESSABLE_ENTITY:
        responses[str(HTTP_422_UNPROCESSABLE_ENTITY)] = {
            "description": "Validation Error",
            "content": {"application/json": {"schema": {"$ref": REF_PREFIX + "HTTPValidationError"}}},
        }

    operation["responses"] = responses

    # Security
    security_definitions: Dict[str, Any] = {}
    operation_security: List[Dict[str, Any]] = []
    sec_defs, op_sec = get_openapi_security_definitions(flat_dependant)
    if sec_defs:
        security_definitions.update(sec_defs)
    if op_sec:
        operation_security = op_sec
        operation["security"] = operation_security

    return operation, security_definitions


def get_openapi_path(
    *,
    route: routing.APIRoute,
    schema_generator: GenerateJsonSchema,
    model_name_map: ModelNameMap,
    field_mapping: Dict[
        Tuple[ModelField, Literal["validation", "serialization"]], JsonSchemaValue
    ],
    generate_unique_operation_id: bool = True,
    separate_input_output_schemas: bool = True,
) -> Tuple[str, Dict[str, Any], Dict[str, Any]]:
    """
    Construct the OpenAPI path item (mapping HTTP methods to operation objects)
    for a given APIRoute.

    Returns a tuple of (path, path_item_object, security_definitions).
    """
    path = route.path_format
    path_item: Dict[str, Any] = {}
    security_definitions: Dict[str, Any] = {}

    methods = route.methods or set()
    for method in methods:
        method_lower = method.lower()
        if method_lower == "head":
            continue
        response_field = None
        response_class = route.response_class or Response
        status_code = route.status_code or 200
        # Try to extract response model field if available
        if getattr(route, "response_field", None) is not None:
            response_field = route.response_field
        operation, sec_defs = get_openapi_operation_metadata(
            route=route,
            dependant=route.dependant,
            response_field=response_field,
            response_class=response_class,
            status_code=status_code,
            schema_generator=schema_generator,
            model_name_map=model_name_map,
            field_mapping=field_mapping,
            generate_unique_operation_id=generate_unique_operation_id,
            separate_input_output_schemas=separate_input_output_schemas,
        )
        if sec_defs:
            security_definitions.update(sec_defs)
        path_item[method_lower] = operation
    return path, path_item, security_definitions


def _get_route_app(route: BaseRoute) -> Any:
    """
    Helper to traverse routes produced by include_router or mounted applications.
    """
    return getattr(route, "app", None)


def get_fields_from_routes(routes: Sequence[BaseRoute]) -> Set[ModelField]:
    """
    Extract all ModelField instances that are used across a sequence of routes.

    This helps in collecting model definitions for the OpenAPI components.schemas.
    """
    fields: Set[ModelField] = set()
    for route in routes:
        if not isinstance(route, routing.APIRoute):
            # For routing.Mount and other route containers, recurse into inner routes
            app = _get_route_app(route)
            if app and hasattr(app, "routes"):
                fields.update(get_fields_from_routes(app.routes))
            continue
        route_obj = route
        dependant: Dependant = getattr(route_obj, "dependant", None)
        if dependant is None:
            continue
        flat = get_flat_dependant(dependant)
        params = get_flat_params(flat)
        for p in params:
            if isinstance(p, ModelField):
                fields.add(p)
        # Also add response field if present
        if getattr(route_obj, "response_field", None) is not None:
            fields.add(route_obj.response_field)
    return fields


def get_openapi(
    *,
    title: str,
    version: str,
    routes: Sequence[BaseRoute],
    description: Optional[str] = None,
    openapi_version: str = "3.0.2",
    servers: Optional[List[Dict[str, Any]]] = None,
    openapi_prefix: str = "",
    tags: Optional[List[Dict[str, Any]]] = None,
    external_docs: Optional[Dict[str, Any]] = None,
    generate_unique_operation_id: bool = True,
    model_name_map: Optional[ModelNameMap] = None,
    api_key_prefix: Optional[str] = None,
    security: Optional[List[Dict[str, List[str]]]] = None,
    components: Optional[Dict[str, Any]] = None,
    refs_prefix: str = REF_PREFIX,
    include_in_schema: bool = True,
    separate_input_output_schemas: bool = True,
) -> OpenAPI:
    """
    Generate the OpenAPI schema object for a list of Starlette/FastAPI routes.

    This function aggregates path operations, components (schemas), security
    requirements, and other metadata into a dictionary conforming to the
    OpenAPI specification, then returns a FastAPI OpenAPI model instance.
    """
    # Schema generator and mappings
    if model_name_map is None:
        model_name_map = get_compat_model_name_map()
    schema_generator = GenerateJsonSchema()
    field_mapping: Dict[
        Tuple[ModelField, Literal["validation", "serialization"]], JsonSchemaValue
    ] = {}

    paths: Dict[str, Any] = {}
    components: Dict[str, Any] = components or {}
    components_schemas: Dict[str, Any] = components.get("schemas", {}) if components else {}
    security_definitions: Dict[str, Any] = {}
    encountered_models: Set[Type] = set()
    # Walk routes to build paths and collect model fields
    for route in routes:
        if not getattr(route, "include_in_schema", True):
            continue
        if not isinstance(route, routing.APIRoute):
            # handle mounted apps recursively
            app = _get_route_app(route)
            if app and hasattr(app, "routes"):
                inner_openapi = get_openapi(
                    title=title,
                    version=version,
                    routes=app.routes,
                    description=description,
                    openapi_version=openapi_version,
                    servers=servers,
                    openapi_prefix=openapi_prefix,
                    tags=tags,
                    external_docs=external_docs,
                    generate_unique_operation_id=generate_unique_operation_id,
                    model_name_map=model_name_map,
                    api_key_prefix=api_key_prefix,
                    security=security,
                    components=components,
                    refs_prefix=refs_prefix,
                    include_in_schema=include_in_schema,
                    separate_input_output_schemas=separate_input_output_schemas,
                )
                # Merge inner paths and components
                deep_dict_update(paths, inner_openapi.dict()["paths"])
                comp = inner_openapi.dict().get("components") or {}
                if comp.get("schemas"):
                    components_schemas.update(comp.get("schemas", {}))
                if comp.get("securitySchemes"):
                    security_definitions.update(comp.get("securitySchemes", {}))
            continue

        # For APIRoute
        path, path_item, sec_defs = get_openapi_path(
            route=route,
            schema_generator=schema_generator,
            model_name_map=model_name_map,
            field_mapping=field_mapping,
            generate_unique_operation_id=generate_unique_operation_id,
            separate_input_output_schemas=separate_input_output_schemas,
        )
        if sec_defs:
            security_definitions.update(sec_defs)
        # Merge path_item with existing path
        if path in paths:
            existing = paths[path]
            existing.update(path_item)
            paths[path] = existing
        else:
            paths[path] = path_item

    # Collect schema definitions from all fields found in routes
    fields = get_fields_from_routes(routes)
    definitions = get_definitions(
        fields=fields,
        schema_generator=schema_generator,
        model_name_map=model_name_map,
        field_mapping=field_mapping,
        separate_input_output_schemas=separate_input_output_schemas,
    )

    # Merge definitions into components.schemas
    if definitions:
        components_schemas.update(definitions)

    if components_schemas:
        components["schemas"] = components_schemas
    if security_definitions:
        components.setdefault("securitySchemes", {})
        components["securitySchemes"].update(security_definitions)

    openapi_version = openapi_version or "3.0.2"

    openapi_schema: Dict[str, Any] = {
        "openapi": openapi_version,
        "info": {"title": title, "version": version},
        "paths": paths,
    }
    if description:
        openapi_schema["info"]["description"] = description
    if servers:
        openapi_schema["servers"] = servers
    if tags:
        openapi_schema["tags"] = tags
    if external_docs:
        openapi_schema["externalDocs"] = external_docs
    if components:
        openapi_schema["components"] = components
    if security:
        openapi_schema["security"] = security
    if openapi_prefix:
        openapi_schema["servers"] = openapi_schema.get("servers", [])
        openapi_schema["servers"].insert(0, {"url": openapi_prefix})

    # Return as OpenAPI model instance
    return OpenAPI(**openapi_schema)